class Solution:
    def canChoose(self, groups, nums):
        """
        :type groups: List[List[int]]
        :type nums: List[int]
        :rtype: bool
        """
        i = 0  # Index in nums

        for group in groups:
            found = False
            while i <= len(nums) - len(group):
                if nums[i:i+len(group)] == group:
                    i += len(group)
                    found = True
                    break
                i += 1

            if not found:
                return False

        return True
